SELECT
    vacuum_trend_metrics_id AS vacuumTrendMetricsId,
    collected_at AS collectedAt,
    bloat_ratio AS bloatRatio
FROM vacuum_trend_metrics
WHERE database_id = #{databaseId}
  AND table_name = #{tableName}
  AND collected_at BETWEEN #{startDate} AND #{endDate}
  AND bloat_ratio IS NOT NULL
ORDER BY collected_at ASC

SELECT
    vacuum_trend_metrics_id AS vacuumTrendMetricsId,
    collected_at AS collectedAt,
    dead_tuple_total AS deadTupleTotal
FROM vacuum_trend_metrics
WHERE database_id = #{databaseId}
  AND table_name = #{tableName}
  AND collected_at BETWEEN #{startDate} AND #{endDate}
  AND dead_tuple_total IS NOT NULL
ORDER BY collected_at ASC
